('spanish:8-2-social-media-and-online-safety:mcq:2367fbf9', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"No se debe compartir datos personales.\" data-listen></span><br>Listen. What is the advice?", "options": ["You should not share personal data", "You should always share personal data", "You must always protect your friends", "You should share photos with everyone"]}'::jsonb, '{"answer": 0, "explain": "‘no se debe compartir datos personales’ = you should not share personal data. The traps reverse the negative or swap the object."}'::jsonb),
('spanish:8-2-social-media-and-online-safety:mcq:035a2f98', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Sigo a muchos famosos en las redes sociales.\" data-listen></span><br>Listen. What is being said?", "options": ["I follow lots of celebrities on social media", "I never follow celebrities on social media", "I met lots of celebrities at a concert", "I posted photos of lots of celebrities online"]}'::jsonb, '{"answer": 0, "explain": "‘sigo a muchos famosos’ = I follow lots of celebrities. Trap B negates it; C and D invent different actions."}'::jsonb),
